import 'package:baseball_detector_flutter/views/components/empty_view.dart';
import 'package:baseball_detector_flutter/views/components/paging_helper.dart';
import 'package:baseball_detector_flutter/views/pages/home/sessions/session_details/components/resource_card.dart';
import 'package:collection/collection.dart';
import 'package:flutter/material.dart';
import 'package:hooks_riverpod/hooks_riverpod.dart';

class ResourceListTab extends ConsumerWidget {
  const ResourceListTab({
    required this.resourcePagingData,
    required this.session,
    required this.onRefresh,
    super.key,
  });

  final PagingData<ResourceData> resourcePagingData;
  final Session session;
  final Future<void> Function() onRefresh;

  @override
  Widget build(BuildContext context, WidgetRef ref) {
    if (resourcePagingData.items.isEmpty || session.teamId == null) {
      return EmptyView(
        message: context.l10n.session_details_page__no_data,
      );
    }

    final teamId = session.teamId!;

    return RefreshIndicator(
      onRefresh: onRefresh,
      child: SizedBox(
        height: context.screenHeight,
        child: SingleChildScrollView(
          physics: const AlwaysScrollableScrollPhysics(),
          child: Column(
            children: [
              ...resourcePagingData.items.mapIndexed(
                (index, resource) => Container(
                  margin: const EdgeInsetsDirectional.only(
                    bottom: 8,
                  ),
                  child: ResourceCard(
                    teamId: teamId,
                    session: session,
                    resource: resource,
                    isLastItem: index == resourcePagingData.items.length - 1 &&
                        index != 0,
                  ),
                ),
              ),
              if (resourcePagingData.hasMore)
                EndItemView(
                  visibilityKey: Key(
                    'EndItem_${resourcePagingData.items.length}',
                  ),
                  onScrollEnd: () {
                    ref
                        .read(
                          resourceDataListControllerProvider(
                            teamId: teamId,
                            sessionId: session.id!,
                          ).notifier,
                        )
                        .loadNext();
                  },
                ),
            ],
          ),
        ),
      ),
    );
  }
}

