import 'package:baseball_detector_flutter/views/themes/color_manager.dart';

class EmptyContainer extends HookConsumerWidget {
  const EmptyContainer({
    required this.currentSession,
    required this.player,
    super.key,
  });

  final ValueNotifier<Session> currentSession;
  final Player? player;

  @override
  Widget build(BuildContext context, WidgetRef ref) {
    final theme = Theme.of(context);
    final colorScheme = theme.colorScheme;

    final generateReport = useAIReportGeneration(
      player: player,
      currentSession: currentSession,
    );

    return LayoutBuilder(builder: (context, constraints) {
      final sessionId = currentSession.value.id;
      final teamId = currentSession.value.teamId;

      if (sessionId == null || teamId == null) SizedBox.shrink();

      return SingleChildScrollView(
        physics: const AlwaysScrollableScrollPhysics(),
        child: ConstrainedBox(
          constraints: BoxConstraints(minHeight: constraints.maxHeight),
          child: Center(
            child: AllBallsContainer(
              teamId: teamId!,
              sessionId: sessionId!,
              builder: ({
                required List<Ball> hittingBalls,
                required List<Ball> pitchingBalls,
              }) {
                final hasPitchingBalls = pitchingBalls.isNotEmpty;
                final hasAllPitchTypes = hasPitchingBalls &&
                    !pitchingBalls.any((e) =>
                        e.pitchType == null ||
                        e.pitchType?.pitchType == 'none');

                return Container(
                  width: double.infinity,
                  alignment: Alignment.center,
                  child: Padding(
                    padding: const EdgeInsets.all(20),
                    child: Column(
                      mainAxisSize: MainAxisSize.min,
                      children: [
                        Text(
                          context
                              .l10n.ai_coach_report__request_empty_state_title,
                          style: theme.textTheme.titleLarge?.copyWith(
                            fontWeight: FontWeight.w600,
                          ),
                        ),
                        const Gap(24),
                        Text(
                          context.l10n
                              .ai_coach_report__request_empty_state_subtitle,
                          style: theme.textTheme.bodyMedium?.copyWith(
                            color: colorScheme.onSurfaceVariant,
                          ),
                        ),
                        const Gap(20),
                        requirementRow(
                          context,
                          satisfied: hasPitchingBalls,
                          label: context.l10n
                              .ai_coach_report__request_requirement_pitching_data,
                        ),
                        const Gap(12),
                        requirementRow(
                          context,
                          satisfied: hasAllPitchTypes,
                          label: context.l10n
                              .ai_coach_report__request_requirement_pitch_type,
                        ),
                        const Gap(20),
                        SizedBox(
                          width: double.infinity,
                          child: ElevatedButton.icon(
                            onPressed: () async {
                              await generateReport(
                                hittingBalls: hittingBalls,
                                pitchingBalls: pitchingBalls,
                              );
                            },
                            style: ButtonStyle(
                              shape: WidgetStateProperty.all(
                                RoundedRectangleBorder(
                                  borderRadius: BorderRadius.circular(4),
                                ),
                              ),
                            ),
                            icon: Icon(Icons.auto_fix_high),
                            label: Padding(
                              padding:
                                  const EdgeInsets.symmetric(vertical: 16.0),
                              child: Text(context
                                  .l10n.ai_coach_report__request_button_label),
                            ),
                          ),
                        ),
                      ],
                    ),
                  ),
                );
              },
            ),
          ),
        ),
      );
    });
  }

  Widget requirementRow(
    BuildContext context, {
    required bool satisfied,
    required String label,
  }) {
    final theme = Theme.of(context);
    final colorScheme = theme.colorScheme;
    final borderColor =
        satisfied ? ColorManager.main : colorScheme.outlineVariant;
    final textColor =
        satisfied ? colorScheme.onSurface : colorScheme.onSurfaceVariant;
    final textWeight = satisfied ? FontWeight.w600 : FontWeight.w400;

    return Row(
      children: [
        Checkbox(
          value: satisfied,
          onChanged: null,
          materialTapTargetSize: MaterialTapTargetSize.shrinkWrap,
          visualDensity: VisualDensity.compact,
          shape: RoundedRectangleBorder(
            borderRadius: BorderRadius.circular(100),
          ),
          side: BorderSide(color: borderColor, width: 1.5),
          fillColor: WidgetStateProperty.resolveWith<Color?>(
            (states) => satisfied ? ColorManager.main : Colors.transparent,
          ),
          checkColor: colorScheme.surface,
        ),
        const Gap(12),
        Expanded(
          child: Column(
            crossAxisAlignment: CrossAxisAlignment.start,
            mainAxisAlignment: MainAxisAlignment.center,
            children: [
              Text(
                label,
                style: theme.textTheme.bodyMedium?.copyWith(
                  color: textColor,
                  fontWeight: textWeight,
                ),
              ),
            ],
          ),
        ),
      ],
    );
  }
}

