import 'package:gap/gap.dart';
import 'package:hooks_riverpod/hooks_riverpod.dart';

// Project imports:
import 'package:baseball_detector_flutter/data/models/player.dart';
import 'package:baseball_detector_flutter/data/models/session.dart';
import 'package:baseball_detector_flutter/views/pages/home/sessions/components/all_balls_container.dart';
import 'package:baseball_detector_flutter/views/pages/home/sessions/session_details/ai_coach_report/hooks/use_ai_report_generation.dart';

class ReportGenerationStatusContent extends HookConsumerWidget {
  const ReportGenerationStatusContent({
    required this.player,
    required this.title,
    required this.description,
    required this.buttonLabel,
    required this.currentSession,
    super.key,
  });

  final Player? player;
  final String title;
  final String description;
  final String buttonLabel;
  final ValueNotifier<Session> currentSession;

  @override
  Widget build(BuildContext context, WidgetRef ref) {
    final theme = Theme.of(context);
    final colorScheme = theme.colorScheme;
    final generateReport = useAIReportGeneration(
      player: player,
      currentSession: currentSession,
    );

    return LayoutBuilder(
      builder: (context, constraints) {
        final sessionId = currentSession.value.id;
        final teamId = currentSession.value.teamId;

        if (sessionId == null || teamId == null) SizedBox.shrink();

        return SingleChildScrollView(
          physics: const AlwaysScrollableScrollPhysics(),
          child: ConstrainedBox(
            constraints: BoxConstraints(minHeight: constraints.maxHeight),
            child: Center(
              child: AllBallsContainer(
                teamId: teamId!,
                sessionId: sessionId!,
                builder: ({
                  required pitchingBalls,
                  required hittingBalls,
                }) {
                  return Padding(
                    padding: const EdgeInsets.symmetric(
                      horizontal: 24,
                      vertical: 28,
                    ),
                    child: Column(
                      mainAxisSize: MainAxisSize.min,
                      children: [
                        Text(
                          title,
                          style: theme.textTheme.titleMedium?.copyWith(
                            fontWeight: FontWeight.w600,
                            color: colorScheme.onSurface,
                          ),
                          textAlign: TextAlign.center,
                        ),
                        const Gap(8),
                        Text(
                          description,
                          style: theme.textTheme.bodyMedium?.copyWith(
                            color: colorScheme.onSurfaceVariant,
                          ),
                          textAlign: TextAlign.center,
                        ),
                        const Gap(24),
                        SizedBox(
                          width: double.infinity,
                          child: ElevatedButton.icon(
                            onPressed: () async {
                              await generateReport(
                                hittingBalls: hittingBalls,
                                pitchingBalls: pitchingBalls,
                              );
                            },
                            style: ButtonStyle(
                              shape: WidgetStateProperty.all(
                                RoundedRectangleBorder(
                                  borderRadius: BorderRadius.circular(4),
                                ),
                              ),
                            ),
                            icon: const Icon(Icons.refresh),
                            label: Padding(
                              padding: const EdgeInsets.symmetric(vertical: 16),
                              child: Text(buttonLabel),
                            ),
                          ),
                        ),
                      ],
                    ),
                  );
                },
              ),
            ),
          ),
        );
      },
    );
  }
}

