// ---------- mock helpers ----------

Widget _buildScenarioContainer(
  BuildContext context, {
  required Player player,
  required AsyncValue<AICoachReport?> reportState,
}) {
  final report = reportState.asData?.value;
  return ColoredBox(
    color: Theme.of(context).scaffoldBackgroundColor,
    child: AICoachReportContainer(
      currentSession: _createSessionNotifier(
        player: player,
        report: report,
      ),
      player: player,
      reportState: reportState,
    ),
  );
}

ValueNotifier<Session> _createSessionNotifier({
  required Player player,
  AICoachReport? report,
}) {
  return ValueNotifier(
    Session(
      id: 'sessionId',
      teamId: 'teamId',
      title: 'Bullpen Session',
      playerId: player.id,
      player: player,
      createdAt: _kVrtNow,
      updatedAt: _kVrtNow,
      aiCoachReport: report,
    ),
  );
}

Player _mockPlayer() {
  return Player(
    id: 'playerId',
    teamId: 'teamId',
    name: 'Test Player',
    birthday: DateTime.utc(2000, 1, 1),
    pitchingHand: Handedness.right,
    createdAt: _kVrtNow,
    updatedAt: _kVrtNow,
  );
}
